#include <bits/stdc++.h>
using namespace std;
const int maxn=1e6+5;
long long a[maxn],ma=0,mi=1e18;
int n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        if(a[i]>ma)ma=a[i];
        if(a[i]<mi)mi=a[i];
    }
    for(int i=1;i<=n;i++){
        cout<<ma-a[i]<<' ';
    }
    cout<<"\n";
    for(int i=1;i<=n;i++)cout<<a[i]-mi<<' ';
    return 0;
}
